module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] valid_next_count;

  always @(posedge clk) begin
    if (reset) begin
      valid_next_count <= 4'b0000;
    end
    else begin
      valid_next_count <= count + 1;
    end
  end

  assign count = valid_next_count;

endmodule
